unordered_map<string, int> m;
m.insert({"x", 10});
m.emplace("y", 20);

auto it = m.find("x");
if (it != m.end()) {
    cout << it->first << " = " << it->second << endl;  // x = 10
}

if (m.find("z") == m.end()) {
    cout << "z not found" << endl;
}

