sections.example:
unordered_map<string, int> scores = {{"Alice", 90}, {"Bob", 85}, {"Carol", 95}};

// Structured bindings (C++17)
for (auto& [name, score] : scores) {
    cout << name << ": " << score << endl;
}

// Classic style
for (auto it = scores.begin(); it != scores.end(); it++) {
    cout << it->first << " -> " << it->second << endl;
}

